query:
-- لوحات التحكم
UPDATE permissions SET description = 'السماح بعرض لوحة التحكم الرئيسية مع الإحصائيات العامة والمؤشرات الأساسية للنظام' WHERE code = 'view_main_dashboard';
UPDATE permissions SET description = 'السماح بعرض لوحة التحكم التنفيذية مع التقارير التفصيلية والتحليلات المتقدمة' WHERE code = 'view_executive_dashboard';

-- الموارد البشرية
UPDATE permissions SET description = 'السماح بعرض قائمة جميع العمال مع تفاصيلهم الأساسية (الاسم، رقم الهوية، المجموعة، المسمى الوظيفي)' WHERE code = 'view_workers';
UPDATE permissions SET description = 'السماح بإضافة عمال جدد إلى النظام مع إدخال بياناتهم الكاملة وإنشاء QR Code خاص بكل عامل' WHERE code = 'create_workers';
UPDATE permissions SET description = 'السماح بتعديل بيانات العمال الموجودين (الاسم، المجموعة، المسمى الوظيفي، رقم الهاتف، الراتب)' WHERE code = 'edit_workers';
UPDATE permissions SET description = 'السماح بحذف العمال من النظام بشكل نهائي (عملية حساسة تتطلب صلاحيات عالية)' WHERE code = 'delete_workers';
UPDATE permissions SET description = 'السماح بعرض قائمة المجموعات (فرق العمل) مع عدد العمال في كل مجموعة' WHERE code = 'view_groups';
UPDATE permissions SET description = 'السماح بإنشاء مجموعات عمل جديدة لتنظيم العمال حسب الأقسام أو المشاريع' WHERE code = 'create_groups';

-- الحضور والانصراف
UPDATE permissions SET description = 'السماح بعرض سجل الحضور والانصراف اليومي لجميع العمال مع الأوقات الفعلية' WHERE code = 'view_attendance';
UPDATE permissions SET description = 'السماح بتعديل سجلات الحضور والانصراف (تصحيح الأخطاء، إضافة تسجيلات يدوية)' WHERE code = 'edit_attendance';
UPDATE permissions SET description = 'السماح بعرض تقارير الحضور الشاملة (التأخير، الغياب، ساعات العمل الفعلية)' WHERE code = 'view_attendance_reports';
UPDATE permissions SET description = 'السماح بتصدير بيانات الحضور إلى ملفات Excel أو PDF لأغراض الأرشفة والمراجعة' WHERE code = 'export_attendance';
UPDATE permissions SET description = 'السماح بإدارة جداول أيام العمل والإجازات الرسمية والعطلات الأسبوعية' WHERE code = 'manage_work_days';

-- المالية والرواتب
UPDATE permissions SET description = 'السماح بعرض دفعات الرواتب الشهرية مع تفاصيل كل دفعة (المبلغ الإجمالي، عدد العمال، التاريخ)' WHERE code = 'view_payroll';
UPDATE permissions SET description = 'السماح بالموافقة النهائية على دفعات الرواتب قبل الصرف (صلاحية إدارية عليا)' WHERE code = 'approve_payroll';
UPDATE permissions SET description = 'السماح بعرض التقارير المالية الشاملة (إجمالي الرواتب، التكاليف، الاستثناءات المالية)' WHERE code = 'view_reports';
UPDATE permissions SET description = 'السماح بتصدير التقارير المالية والبيانات المحاسبية إلى ملفات Excel أو PDF' WHERE code = 'export_data';
UPDATE permissions SET description = 'السماح بعرض وإدارة مراكز التكلفة (الفروع، الأقسام، المشاريع) لتوزيع التكاليف' WHERE code = 'view_cost_centers';

-- إعدادات النظام
UPDATE permissions SET description = 'السماح بعرض قائمة المستخدمين مع أدوارهم وصلاحياتهم' WHERE code = 'view_users';
UPDATE permissions SET description = 'السماح بإضافة مستخدمين جدد للنظام مع تعيين أدوارهم وكلمات السر' WHERE code = 'create_users';
UPDATE permissions SET description = 'السماح بتعديل بيانات المستخدمين (الاسم، الدور، كلمة السر، الصلاحيات)' WHERE code = 'edit_users';

